@app.route("/token", methods=["POST"])
def token():
    grant_type = request.form.get("grant_type")
    if grant_type != "authorization_code":
        return jsonify(error="unsupported_grant_type"), 400

    code = request.form.get("code")
    redirect_uri = request.form.get("redirect_uri")
    client_id = request.form.get("client_id")
    client_secret = request.form.get("client_secret")

    if not client_id or client_id not in clients:
        return jsonify(error="invalid_client"), 401

    if clients[client_id]["client_secret"] != client_secret:
        return jsonify(error="invalid_client"), 401

    if not redirect_uri or not validate_redirect_uri(client_id, redirect_uri):
        return jsonify(error="invalid_request", error_description="Invalid redirect_uri"), 400

    data = auth_codes.get(code)
    if not data:
        return jsonify(error="invalid_grant"), 400

    if data["client_id"] != client_id:
        return jsonify(error="invalid_grant"), 400

    if data["exp"] < now():
        auth_codes.pop(code, None)
        return jsonify(error="invalid_grant"), 400

    # Enforce exact match to the redirect_uri used in /authorize (still validated with startswith at registration)
    if data["redirect_uri"] != redirect_uri:
        return jsonify(error="invalid_grant"), 400

    auth_codes.pop(code, None)

    token = secrets.token_urlsafe(32)
    access_tokens[token] = {
        "client_id": client_id,
        "sub": data["sub"],
        "scope": data["scope"],
        "iat": now(),
        "exp": now() + ACCESS_TOKEN_TTL_SECONDS,
    }

    return jsonify(
        access_token=token,
        token_type="Bearer",
        expires_in=ACCESS_TOKEN_TTL_SECONDS,
        scope=data["scope"],
    )


def get_bearer_token():
    auth = request.headers.get("Authorization", "")
    if auth.lower().startswith("bearer "):
        return auth.split(None, 1)[1].strip()
    return None


@app.route("/userinfo", methods=["GET"])
def userinfo():
    token = get_bearer_token()
    if not token or token not in access_tokens:
        return jsonify(error="invalid_token"), 401

    data = access_tokens[token]
    if data["exp"] < now():
        access_tokens.pop(token, None)
        return jsonify(error="invalid_token"), 401

    return jsonify(sub=data["sub"], scope=data["scope"])


@app.route("/.well-known/openid-configuration", methods=["GET"])
def discovery():
    base = request.host_url.rstrip("/")
    return jsonify(
        issuer=base,
        authorization_endpoint=base + "/authorize",
        token_endpoint=base + "/token",
        userinfo_endpoint=base + "/userinfo",
        response_types_supported=["code"],
        grant_types_supported=["authorization_code"],
        token_endpoint_auth_methods_supported=["client_secret_post"],
        scopes_supported=["openid", "profile", "email", "read", "write"],
    )


